-- Dummy Demo Database Initialization
-- Minimal setup for demonstration purposes

-- Create extensions
CREATE EXTENSION IF NOT EXISTS vector;
CREATE EXTENSION IF NOT EXISTS postgis;

-- Create demo user role (optional for Directus)
CREATE USER IF NOT EXISTS demo_user WITH PASSWORD 'demo123';
GRANT ALL PRIVILEGES ON DATABASE matchgorithm TO demo_user;

-- Create simple demo table
CREATE TABLE IF NOT EXISTS demo_items (
    id SERIAL PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    description TEXT,
    category VARCHAR(100),
    embedding vector(384),  -- CLIP embedding dimension
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

